// src/components/PostReader.jsx
import { useState } from "react";
import { likePost } from "../firebase/posts";

function formatDate(ts) {
  if (!ts) return "Recently";
  const d = ts.seconds ? new Date(ts.seconds * 1000) : new Date(ts);
  return d.toLocaleDateString("en-US", {
    weekday: "long", year: "numeric", month: "long", day: "numeric",
  });
}

const CATEGORY_COLORS = {
  Technology: { bg: "#dbeafe", color: "#1d4ed8" },
  Agile:      { bg: "#d1fae5", color: "#059669" },
  Design:     { bg: "#ede9fe", color: "#7c3aed" },
  Business:   { bg: "#fee2e2", color: "#dc2626" },
  Tutorial:   { bg: "#fef3c7", color: "#d97706" },
  Innovation: { bg: "#e0f2fe", color: "#0284c7" },
  General:    { bg: "#f1f5f9", color: "#64748b" },
};

export default function PostReader({ post, onClose }) {
  const [likes, setLikes] = useState(post.likes || 0);
  const [liked, setLiked] = useState(false);
  const [imgError, setImgError] = useState(false);
  const catStyle = CATEGORY_COLORS[post.category] || CATEGORY_COLORS.General;

  const handleLike = async () => {
    if (liked) return;
    setLiked(true);
    setLikes((n) => n + 1);
    try {
      await likePost(post.id, likes);
    } catch { /* demo mode */ }
  };

  const paragraphs = (post.content || "").split("\n").filter(Boolean);

  return (
    <div style={s.backdrop} onClick={(e) => e.target === e.currentTarget && onClose()}>
      <div style={s.modal}>

        <button style={s.closeBtn} onClick={onClose}>✕</button>

        {/* Hero image */}
        {post.imageUrl && !imgError && (
          <div style={s.heroImg}>
            <img
              src={post.imageUrl}
              alt={post.title}
              style={{ width: "100%", height: "100%", objectFit: "cover", display: "block" }}
              onError={() => setImgError(true)}
            />
            <div style={s.heroOverlay} />
          </div>
        )}

        <div style={s.content}>
          {/* Category */}
          <span style={{ ...s.cat, background: catStyle.bg, color: catStyle.color }}>
            {post.category || "General"}
          </span>

          {/* Title */}
          <h1 style={s.title}>{post.title}</h1>

          {/* Meta */}
          <div style={s.meta}>
            <div style={s.authorRow}>
              <div style={s.avatar}>{(post.author || "A")[0].toUpperCase()}</div>
              <div>
                <div style={s.authorName}>{post.author || "Anonymous"}</div>
                <div style={s.date}>{formatDate(post.createdAt)}</div>
              </div>
            </div>
            <div style={s.metaRight}>
              <span style={s.metaItem}>👁️ {post.views || 0}</span>
              <span style={s.metaItem}>❤️ {likes}</span>
            </div>
          </div>

          <div style={s.divider} />

          {/* Body */}
          <div style={s.body}>
            {paragraphs.map((para, i) => {
              if (para.startsWith("•") || para.match(/^\d+\./)) {
                return (
                  <p key={i} style={{ ...s.para, paddingLeft: 20 }}>
                    {para}
                  </p>
                );
              }
              return <p key={i} style={s.para}>{para}</p>;
            })}
          </div>

          {/* Like */}
          <div style={s.likeSection}>
            <button
              style={{
                ...s.likeBtn,
                background: liked ? "#fee2e2" : "var(--bg)",
                borderColor: liked ? "#fca5a5" : "var(--border)",
                transform: liked ? "scale(1.05)" : "scale(1)",
              }}
              onClick={handleLike}
              onMouseEnter={(e) => !liked && (e.currentTarget.style.borderColor = "var(--blue-light)")}
              onMouseLeave={(e) => !liked && (e.currentTarget.style.borderColor = "var(--border)")}
            >
              {liked ? "❤️" : "🤍"} {liked ? "Liked!" : "Like this post"} · {likes}
            </button>
          </div>

          {/* Tags footer */}
          <div style={s.tagsRow}>
            <span style={{ ...s.tag, background: catStyle.bg, color: catStyle.color }}>
              #{(post.category || "General").toLowerCase()}
            </span>
            <span style={s.tag}>#aeroblog</span>
            <span style={s.tag}>#firebase</span>
            <span style={s.tag}>#react</span>
          </div>
        </div>
      </div>
    </div>
  );
}

const s = {
  backdrop: {
    position: "fixed", inset: 0, zIndex: 200,
    background: "rgba(12,12,20,0.65)",
    backdropFilter: "blur(12px)",
    display: "flex", alignItems: "center", justifyContent: "center",
    padding: 24,
  },
  modal: {
    background: "#fff", borderRadius: "var(--radius-lg)",
    width: "100%", maxWidth: 780,
    maxHeight: "92vh", overflowY: "auto",
    position: "relative",
    animation: "slideDown 0.3s ease",
  },
  closeBtn: {
    position: "fixed", top: "calc(4% + 14px)", right: "calc(50% - 390px + 14px)",
    width: 38, height: 38, borderRadius: "50%",
    background: "rgba(255,255,255,0.95)", border: "1px solid var(--border)",
    fontSize: "0.95rem", cursor: "pointer", zIndex: 10,
    display: "flex", alignItems: "center", justifyContent: "center",
    boxShadow: "0 2px 8px rgba(0,0,0,0.1)",
  },
  heroImg: { height: 320, position: "relative", overflow: "hidden" },
  heroOverlay: {
    position: "absolute", inset: 0,
    background: "linear-gradient(to top, rgba(255,255,255,0.6) 0%, transparent 60%)",
  },
  content: { padding: "32px 48px 44px" },
  cat: {
    display: "inline-block",
    padding: "4px 14px", borderRadius: 100,
    fontSize: "0.74rem", fontWeight: 700, fontFamily: "var(--font-display)",
    marginBottom: 16,
  },
  title: {
    fontSize: "clamp(1.6rem, 3vw, 2.2rem)", fontWeight: 800,
    fontFamily: "var(--font-display)", color: "var(--ink)",
    lineHeight: 1.2, letterSpacing: "-0.5px", marginBottom: 20,
  },
  meta: {
    display: "flex", alignItems: "center",
    justifyContent: "space-between", flexWrap: "wrap", gap: 12,
  },
  authorRow: { display: "flex", alignItems: "center", gap: 10 },
  avatar: {
    width: 36, height: 36, borderRadius: "50%",
    background: "var(--blue)", color: "#fff",
    fontSize: "0.9rem", fontWeight: 700, fontFamily: "var(--font-display)",
    display: "flex", alignItems: "center", justifyContent: "center",
  },
  authorName: {
    fontSize: "0.88rem", fontWeight: 700, fontFamily: "var(--font-display)", color: "var(--ink)",
  },
  date: { fontSize: "0.76rem", color: "var(--muted)" },
  metaRight: { display: "flex", gap: 16 },
  metaItem: { fontSize: "0.82rem", color: "var(--mid)" },
  divider: { height: 1, background: "var(--border)", margin: "24px 0" },
  body: { display: "flex", flexDirection: "column", gap: 16 },
  para: {
    fontSize: "1.03rem", lineHeight: 1.82,
    color: "#2d3748", fontFamily: "var(--font-body)",
  },
  likeSection: {
    display: "flex", justifyContent: "center",
    marginTop: 36, paddingTop: 32, borderTop: "1px solid var(--border)",
  },
  likeBtn: {
    padding: "12px 28px", borderRadius: 100,
    border: "1.5px solid var(--border)", background: "var(--bg)",
    fontFamily: "var(--font-display)", fontWeight: 700, fontSize: "0.9rem",
    cursor: "pointer", transition: "all 0.2s",
  },
  tagsRow: {
    display: "flex", gap: 8, flexWrap: "wrap", marginTop: 20,
  },
  tag: {
    background: "var(--bg-2)", color: "var(--mid)",
    padding: "3px 12px", borderRadius: 100,
    fontSize: "0.76rem", fontFamily: "var(--font-display)", fontWeight: 600,
  },
};
